import java.util.*;

class NumberContainers {
    private HashMap<Integer, Integer> indices = new HashMap<>();
    private TreeMap<Integer, TreeSet<Integer>> nums = new TreeMap<>();

    public NumberContainers() {
    }

    public void change(int index, int number) {
        if (indices.containsKey(index)) {
            int old_number = indices.get(index);
            nums.get(old_number).remove(index);
            if (nums.get(old_number).isEmpty()) {
                nums.remove(old_number);
            }
        }
        indices.put(index, number);
        nums.putIfAbsent(number, new TreeSet<>());
        nums.get(number).add(index);
    }

    public int find(int number) {
        if (nums.containsKey(number)) {
            return nums.get(number).first();
        }
        return -1;
    }
}
